        String saleId = q.dip(USER_ID);
        //mail中的連結加入email以辨識是誰瀏覽
        encodeEmail = new DES().encrypt(saleId);
        encodeEmail = java.net.URLEncoder.encode(encodeEmail, "utf-8");
        initMessage = subject+"<br/>請按 <a href='" + url + encodeEmail + "'>這裡</a> 進入瀏覽報表 ";        
        message = "<img src='https://"+request.getServerName() + "/cust/diageo/mailHeader.jpg' />"
                + "<div style='line-height:200%;margin-left:50px'>"
                + "Hi " + saleName + ",<br/>" + initMessage
                + "</div><img src='https://"+request.getServerName() + "/cust/diageo/mailFooter.jpg' />";
        Notification.createNotification(AP_NAME, saleId, subject, message, url + encodeEmail, MAIL_TYPE);

        q.goback();

        //to sales manager
        out.println("確認完成，系統已寄信通知業務 " + saleName + "囉！");
        //out.println("確認完成，系統已寄信通知業務 " + saleName + "與業務經理 " + smName + "囉！");

